// Package v4 contains all v4 handlers
package v4

import (
	"code.in.spdigital.sg/sp-digital/golang/web.v2/middleware"
	"code.in.spdigital.sg/sp-digital/infinity/pkg/basiciam"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/downtime"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/account"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/byob"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/emailsubscription"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/greengoals"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/pledge"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/smrd"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/usage"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v4/user"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/handler"
	"github.com/go-chi/chi/v5"
)

// Router registers handlers to the router provided in the argument
func Router(r chi.Router) {
	// Middlewares

	// Grouped routes
	r.Group(external)
	r.Group(internal)
}

// external is the external chi.Router.Group routes
func external(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) //5MB

	r.Group(authenticated)
	r.Group(public)
}

// Deprecated: the function will be removed 3 months after moving behind mulesoft
// authenticated is the authenticated chi.Router.Group
func authenticated(r chi.Router) {
	// Authentication middleware
	r.Use(authc.Middleware(authc.Config{
		Scope:   true,
		IDToken: true,
	}))

	// Routes
	authenticatedRoutes(r)
}

func authenticatedRoutes(r chi.Router) {
	// Routes without details
	// TODO - remove this once mobile team has removed them
	r.Post("/v4/pledge/status", handler.Wrap(pledge.RetrievePledgeStatus)) // Deprecated
	// ------------------------
	// Details-required routes
	// ------------------------
	r.Group(func(r chi.Router) {
		// BP details middleware
		r.Use(bp.DetailsByJWTMiddleware())

		// Routes

		// Charts
		r.Get("/v4/charts/{premises_id}", handler.Wrap(usage.Charts))
		r.Get("/v4/greengoals/districts", handler.Wrap(greengoals.DistrictsDynamic))
		r.Get("/v4/greengoals/targets", handler.Wrap(greengoals.TargetsDynamic))
		r.Delete("/v4/greengoals/cache", handler.Wrap(greengoals.InvalidateGreenGoalsCache))

		// SMRD
		r.Route("/v4/smrd", func(r chi.Router) {
			r.Post("/", handler.Wrap(smrd.Submit))
		})
	})
}

// public is the public chi.Router.Group routes
func public(r chi.Router) {
	// Routes
	r.Post("/v4/email/subscription", handler.Wrap(emailsubscription.Register))
	r.Get("/v4/public/greengoals/districts", handler.Wrap(greengoals.DistrictsStatic))
	r.Get("/v4/public/greengoals/charts/district", handler.Wrap(greengoals.GetDistrictConsumption))
	r.Get("/v4/public/greengoals/charts/country", handler.Wrap(greengoals.GetNationalConsumption))
	r.Get("/v4/public/greengoals/targets", handler.Wrap(greengoals.TargetsStatic))
}

// internal is the OAuth2 machine-to-machine chi.Router.Group
func internal(r chi.Router) {
	// Middlewares
	// Access token middleware
	r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
	// Audience middleware
	r.Use(basiciam.RequireClaimAudience(auth0.AudM2M))

	// Routes

	// User
	r.Route("/v4/user", func(r chi.Router) {
		// Retrieve IAM_ID from formdata
		r.Use(bp.DetailsByFormMiddleware())

		// Account details
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadAccount)).
			Get("/accounts", handler.Wrap(user.RetrieveAccounts))

		// Chart
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadChart)).
			Get("/charts/{premises_id}", handler.Wrap(usage.Charts))
	})

	// Njord Billing
	r.Route("/v4/accounts", func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadAccount))

		r.Get("/all", handler.Wrap(account.RetrieveAccountsByIAM))
		r.Get("/outstanding", handler.Wrap(account.OutstandingBySystem))
	})

	// BYOB
	r.Route("/v4/byob", func(r chi.Router) {
		// Temporarily use GraphQL scope to protect BYOB admin routes
		// TODO: Create appropriate scope/permissions on Auth0
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadGraphQL))

		r.Get("/redemptions/report", handler.Wrap(byob.GenerateRedemptionReport))
	})
}

// GatewayAuthenticatedRoutes is the gateway routes behind b2c mulesoft
func GatewayAuthenticatedRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) //5MB

	// Parse JWTClaims from SecurityContext and store in Context
	r.Use(authc.JWTClaimsSecurityContextMiddleware())

	// Scope middleware
	r.Use(auth0.MulesoftRequireScopesOrMatcherMiddleware(auth0.ScopeUtilities, auth0.ScopeRBAC))
	r.Use(auth0.MulesoftRequireScope(auth0.ScopeInfinity))
	// Routes
	authenticatedRoutes(r)
}

// GatewayPublicRoutes is the gateway public routes behind heimdall-public mulesoft
func GatewayPublicRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) //5MB

	r.Group(public)
	r.Group(func(r chi.Router) {
		r.Post("/v4/smrd/anonymous/submit", handler.Wrap(smrd.SubmitAnonymously))
	})
}

// Package v3 contains all v3 handlers
package v3

import (
	"code.in.spdigital.sg/sp-digital/golang/web.v2/middleware"
	"code.in.spdigital.sg/sp-digital/infinity/pkg/basiciam"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/health"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/account"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/ami"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/authc"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bill"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/bp"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/broadcast/billnotification"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/broadcast/paymentnotification"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/broadcast/smrdnotification"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/datastream"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/downtime"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/ebill"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/incident"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/oem"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/ppms"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/premise"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/app/v3/smrd"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/handler"
	"github.com/go-chi/chi/v5"
)

// Router registers handlers to the router provided in the argument
func Router(r chi.Router) {
	// Middlewares

	// Grouped routes
	r.Group(external)
	r.Group(internal)
}

// external is the external chi.Router.Group routes
func external(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) // 5MB

	r.Group(public)
	r.Group(authenticated)
}

// public is the public chi.Router.Group routes
func public(r chi.Router) {
	// Routes
	r.Get("/v3/status", handler.Wrap(health.Check(nil)))
	r.Post("/v3/incident/report", handler.Wrap(incident.Report))
}

// Deprecated: the function will be removed 3 months after moving behind mulesoft
// authenticated is the authenticated chi.Router.Group
func authenticated(r chi.Router) {
	// Authentication middleware
	r.Use(authc.Middleware(authc.Config{
		Scope:   true,
		IDToken: true,
	}))

	authenticatedRoutes(r)
}

// GatewayAuthenticatedRoutes is the gateway authenticated routes behind b2c mulesoft
func GatewayAuthenticatedRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) // 5MB

	// Parse JWTClaims from SecurityContext and store in Context
	r.Use(authc.JWTClaimsSecurityContextMiddleware())

	r.Group(func(r chi.Router) {
		// Scope middleware
		r.Use(auth0.MulesoftRequireScopesOrMatcherMiddleware(auth0.ScopeUtilities, auth0.ScopeRBAC))
		r.Use(auth0.MulesoftRequireScope(auth0.ScopeInfinity))
		authenticatedRoutes(r)
	})
}

// GatewayPublicRoutes is the gateway public routes behind heimdall-public mulesoft
func GatewayPublicRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) // 5MB

	r.Group(public)
	r.Group(func(r chi.Router) {
		r.Get("/v3/smrd/anonymous/meter/{meter_id}", handler.Wrap(smrd.GetMeterDetailsFromMeterIDAnonymously))
		r.Post("/v3/smrd/anonymous/submit", handler.Wrap(smrd.SubmitAnonymously))
	})
}

func authenticatedRoutes(r chi.Router) {
	// Routes
	r.Delete("/v3/me/cache", handler.Wrap(bp.InvalidateCachedDetails))

	// ------------------------
	// Details-required routes
	// ------------------------
	r.Group(func(r chi.Router) {
		// BP details middleware
		r.Use(bp.DetailsByJWTMiddleware())
		// Datastream middleware
		r.Use(datastream.BPDetailsMiddleware())

		// Routes
		r.Get("/v3/me", handler.Wrap(bp.RetrieveDetails))

		r.Get("/v3/ppms/balance/{premise_id}", handler.Wrap(ppms.Balance))
		r.Post("/v3/ppms/charts", handler.Wrap(ppms.Charts))

		// AMI
		r.Post("/v3/ami/charts", handler.Wrap(ami.Charts))

		// SMRD
		r.Route("/v3/smrd", func(r chi.Router) {
			r.Get("/{premise_id}", handler.Wrap(smrd.GetDetails))
			r.Post("/elec-meters", handler.Wrap(smrd.GetElecMeters))
			r.Post("/elec-meters/readings", handler.Wrap(smrd.GetElecMeterReadings))
			r.Post("/", handler.Wrap(smrd.Submit))
		})
		r.Route("/v3/smrd-uportal", func(r chi.Router) {
			r.Get("/{premise_id}", handler.Wrap(smrd.GetDetailsUportal))
		})

		// Sharing
		r.Post("/v3/premises/share", handler.Wrap(premise.Share))
		r.Delete("/v3/premises/share", handler.Wrap(premise.DeleteSharedResource))
		r.Put("/v3/premises/share/access", handler.Wrap(premise.ShareAccess))

		// OEM
		r.Get("/v3/oem/signup/calendar/{premise_id}", handler.Wrap(oem.SignUpCalendar))
		r.Post("/v3/oem/signup/wholesale/calendar", handler.Wrap(oem.WholesaleCalendar))
		r.Post("/v3/oem/signup/wholesale", handler.Wrap(oem.Wholesale))

		// e-Bill switch
		r.Get("/v3/ebill/switch", handler.Wrap(ebill.SwitchEligibility))
		r.Post("/v3/ebill/switch", handler.Wrap(ebill.Switch))

		// Account link completion
		r.Post("/v3/account/link/complete", handler.Wrap(account.LinkComplete))
	})
}

// internal is the OAuth2 machine-to-machine chi.Router.Group
func internal(r chi.Router) {
	// Middlewares
	// Access token middleware
	r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
	// Audience middleware
	r.Use(basiciam.RequireClaimAudience(auth0.AudM2M))

	// BP details
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MDeleteBPCache)).
		Delete("/v3/bp/cache", handler.Wrap(bp.RemoveCachedDetails))
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadBpDetails)).
		Get("/v3/bp/details", handler.Wrap(bp.GetBPDetails))

	// Payments
	r.Route("/v3/user", func(r chi.Router) {
		// Retrieve IAM_ID from formdata
		r.Use(bp.DetailsByFormMiddleware())

		// Bills
		r.Route("/bills", func(r chi.Router) {
			r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MReadBill))
			r.Get("/average", handler.Wrap(bill.RetrieveAverageBill))
		})
		// Chart
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadChart)).
			Post("/ami/charts", handler.Wrap(ami.Charts))
	})

	// AMI data
	r.Post("/v3/ami/download", handler.Wrap(ami.DownloadCSV))

	// Notifications
	r.Route("/v3/notify", func(r chi.Router) {
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MCreateNotification))
		r.Post("/bill/statement", handler.Wrap(billnotification.BroadcastPipe)) // Automic triggered notification job for billed statement
		r.Post("/bill/due", handler.Wrap(billnotification.BroadcastHdrTrl))     // Automic triggered notification job for bill due today
		r.Post("/bill/overdue", handler.Wrap(billnotification.BroadcastHdrTrl)) // Automic triggered notification job for bill overdue
		r.Post("/smrd/7d", handler.Wrap(smrdnotification.BroadcastSMRD7d))      // Automic triggered notification job for SMRD-7d reminder
		r.Post("/smrd/3d", handler.Wrap(smrdnotification.BroadcastSMRD3d))      // Automic triggered notification job for SMRD-3d reminder
		r.Post("/smrd/1d", handler.Wrap(smrdnotification.BroadcastSMRD1d))      // Automic triggered notification job for SMRD reminder
		r.Post("/payments", handler.Wrap(paymentnotification.Broadcast))        // Automic triggered notification job for payment success/failure
	})
	// Downtime schedules CRUD
	r.Route("/v3/downtimeschedules", func(r chi.Router) {
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadDowntime)).
			Get("/", handler.Wrap(downtime.HandleGet))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MCreateDowntime)).
			Post("/", handler.Wrap(downtime.HandlePost))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MUpdateDowntime)).
			Put("/", handler.Wrap(downtime.HandlePut))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MReadDowntime)).
			Get("/{id}", handler.Wrap(downtime.HandleGet))
		r.With(basiciam.RequireClaimScope(auth0.ScopeM2MDeleteDowntime)).
			Delete("/{id}", handler.Wrap(downtime.HandleDelete))
	})

	// Shared premises feature toggle
	// Temporarily use this scope just to protect this endpoint and allow EVA Admin
	r.With(basiciam.RequireClaimScope(auth0.ScopeM2MCreateDowntime)).
		Put("/v3/feature/sharedpremises", handler.Wrap(bp.ToggleSharedPremisesFeature))
}

