// Router registers handlers to the router provided in the argument
func Router(r chi.Router) {
	// Middlewares

	// Grouped routes
	r.Group(external)
	// r.Group(internal)
}

// external is the external chi.Router.Group routes
func external(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(5 << (10 * 2))) //5MB

	r.Group(authenticated)
	r.Group(public)
}

// public is the public chi.Router.Group routes
func public(r chi.Router) {
	// Routes
	r.Get("/v5/public/greengoals/targets", handler.Wrap(greengoals.TargetsStatic))
}

// Deprecated: the function will be removed 3 months after moving behind mulesoft
// authenticated is the authenticated chi.Router.Group
func authenticated(r chi.Router) {
	// Authentication middleware
	r.Use(authc.Middleware(authc.Config{
		Scope:   true,
		IDToken: true,
	}))

	// Routes
	authenticatedRoutes(r)
}

func authenticatedRoutes(r chi.Router) {
	// ------------------------
	// Details-required routes
	// ------------------------
	r.Group(func(r chi.Router) {
		// BP details middleware
		r.Use(bp.DetailsByJWTMiddleware())

		// Routes

		// Charts
		r.Get("/v5/greengoals/targets", handler.Wrap(greengoals.TargetsDynamic))
	})
}

// GatewayAuthenticatedRoutes is the gateway routes behind b2c mulesoft
func GatewayAuthenticatedRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(10000)) //10 KB

	// Parse JWTClaims from SecurityContext and store in Context
	r.Use(authc.JWTClaimsSecurityContextMiddleware())

	// Scope middleware
	r.Use(auth0.MulesoftRequireScopesOrMatcherMiddleware(auth0.ScopeUtilities, auth0.ScopeRBAC))
	r.Use(auth0.MulesoftRequireScope(auth0.ScopeInfinity))
	// Routes
	authenticatedRoutes(r)
}

// GatewayPublicRoutes is the gateway public routes behind heimdall-public mulesoft
func GatewayPublicRoutes(r chi.Router) {
	// Middlewares
	r.Use(downtime.Middleware())
	r.Use(middleware.LimitPayload(10000)) //10 KB

	r.Group(public)
}

package bp

import (
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/sap"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/stubs/frcpo/ebs"
)

// HasPremises returns web.Error if the requested premise ID is NOT found in the details
func (d *Details) HasPremises(premiseID string) (PremisesType, error) {
	p, ok := d.GetPremises(premiseID)
	if !ok {
		return PremisesType{}, ErrPremiseUnauthorized
	}
	return p, nil
}

// IsPremisesOwner returns web.Error if the requested premise ID is NOT found in the details
// or user does not own premises
func (d *Details) IsPremisesOwner(premiseID string) (PremisesType, error) {
	p, ok := d.GetPremises(premiseID)
	if !ok {
		return PremisesType{}, ErrPremiseUnauthorized
	}
	if !p.SharedResourceDetails.Owner {
		return PremisesType{}, ErrPremiseUnauthorized
	}
	return p, nil
}

// IsPremiseOwnerOrSharedUserWithFullAccess retrieve premise details of a owner or a shared user with full premise access
func (d *Details) IsPremiseOwnerOrSharedUserWithFullAccess(premiseID string) (PremisesType, error) {
	p, ok := d.GetPremises(premiseID)
	if !ok {
		return PremisesType{}, ErrPremiseUnauthorized
	}

	if !p.SharedResourceDetails.Owner {
		for _, user := range p.SharedResourceDetails.Users {
			//Shared users with full access can view the pdf bills of the premise
			if user.IamID == d.JWT.Sub && user.FullAccess {
				return p, nil
			}
		}
		return PremisesType{}, ErrPremiseUnauthorized
	}

	return p, nil
}

// GetOwnedOrSharedAccountsWithFullAccess retrieve list of account details of a owner or a shared user with full premise access
func (d *Details) GetOwnedOrSharedAccountsWithFullAccess() []AccountsType {
	accounts := []AccountsType{}
	for _, it := range d.Premises {
		if it.SharedResourceDetails.Owner {
			accounts = append(accounts, it.Accounts...)
		} else {
			for _, user := range it.SharedResourceDetails.Users {
				//Shared users with full access can view the pdf bills of the premise
				if user.IamID == d.JWT.Sub && user.FullAccess {
					accounts = append(accounts, it.Accounts...)
				}
			}
		}
	}
	return accounts
}

// GetPremises returns the premises for the provided premise ID
func (d *Details) GetPremises(premiseID string) (PremisesType, bool) {
	for _, p := range d.Premises {
		if p.ID == premiseID {
			return p, true
		}
	}
	return PremisesType{}, false
}

// HasAccount returns web.Error if the requested account number is NOT found in the details
func (d *Details) HasAccount(accNo string) (AccountsType, error) {
	a, ok := d.GetAccount(accNo)
	if !ok {
		return AccountsType{}, ErrAccountUnauthorized
	}
	return a, nil
}

// GetAccount returns the Account for the provided account number
func (d *Details) GetAccount(accNo string) (AccountsType, bool) {
	for _, p := range d.Premises {
		for _, a := range p.Accounts {
			if sap.PadAccountNo(a.AccountNumber) == sap.PadAccountNo(accNo) {
				return a, true
			}
		}
	}
	return AccountsType{}, false
}

// GetAllAccounts returns all the accounts in the details
func (d *Details) GetAllAccounts() []AccountsType {
	accounts := []AccountsType{}
	for _, it := range d.Premises {
		accounts = append(accounts, it.Accounts...)
	}
	return accounts
}

// GetOwnedAccounts returns accounts for owned premises
func (d *Details) GetOwnedAccounts() []AccountsType {
	return d.getAccounts(true)
}

// GetSharedAccounts returns accounts for shared premises
func (d *Details) GetSharedAccounts() []AccountsType {
	return d.getAccounts(false)
}

func (d *Details) getAccounts(isOwner bool) []AccountsType {
	accounts := []AccountsType{}
	for _, it := range d.Premises {
		if it.SharedResourceDetails.Owner == isOwner {
			accounts = append(accounts, it.Accounts...)
		}
	}
	return accounts
}

// GetBPDetails returns the BpNumbersType for the provided BP number
func (d *Details) GetBPDetails(bpNo string) (BpNumbersType, bool) {
	for _, b := range d.BpNumbers {
		if b.BpNumber == bpNo {
			return b, true
		}
	}
	return BpNumbersType{}, false
}

// GetAllActiveAccounts returns all active accounts in the premise
func (p *PremisesType) GetAllActiveAccounts() []AccountsType {
	accounts := []AccountsType{}
	for _, a := range p.Accounts {
		if a.AccountStatus == frcpo.AccountStatusActive {
			accounts = append(accounts, a)
		}
	}
	return accounts
}

// GetActiveEBSAccount returns the active EBS JWTAccount for the JWTPremise
func (p *PremisesType) GetActiveEBSAccount() (AccountsType, bool) {
	for _, a := range p.Accounts {
		if a.System == frcpo.SystemEBS && a.AccountStatus == frcpo.AccountStatusActive {
			return a, true
		}
	}
	return AccountsType{}, false
}

// GetActiveMSSLAccount returns the active MSSL JWTAccount for the JWTPremise
func (p *PremisesType) GetActiveMSSLAccount() (AccountsType, bool) {
	for _, a := range p.Accounts {
		if a.System == frcpo.SystemMSSL && a.AccountStatus == frcpo.AccountStatusActive {
			return a, true
		}
	}
	return AccountsType{}, false
}

// GetEBSAccount returns the latest (active or inactive) EBS JWTAccount for the JWTPremise
// Assumption: premises accounts are sorted using lessAccountType
func (p *PremisesType) GetEBSAccount() (AccountsType, bool) {
	for _, a := range p.Accounts {
		if a.System == frcpo.SystemEBS {
			return a, true
		}
	}
	return AccountsType{}, false
}

// GetMSSLAccount returns the latest (active or inactive) MSSL Account
func (p *PremisesType) GetMSSLAccount() (AccountsType, bool) {
	for _, a := range p.Accounts {
		if a.System == frcpo.SystemMSSL {
			return a, true
		}
	}
	return AccountsType{}, false
}

// GetEBSOrMSSLAccount returns the latest (active or inactive) EBS account, if not available then a MSSL Account if exist
func (p *PremisesType) GetEBSOrMSSLAccount() (AccountsType, bool) {
	accType, found := p.GetEBSAccount()
	if !found {
		accType, found = p.GetMSSLAccount()
	}
	return accType, found
}

// GetAllContestableDetails returns all contestable details in the details
func (d *Details) GetAllContestableDetails() []ContestableDetailsType {
	contestableDetails := []ContestableDetailsType{}
	for _, it := range d.Premises {
		if it.ContestableDetails.SignedUp {
			contestableDetails = append(contestableDetails, it.ContestableDetails)
		}
	}
	return contestableDetails
}

// GetOwnedContestableDetails returns contestable details for owned premises
func (d *Details) GetOwnedContestableDetails() []ContestableDetailsType {
	return d.getContestableDetails(true)
}

// GetSharedContestableDetails returns contestable details for shared premises
func (d *Details) GetSharedContestableDetails() []ContestableDetailsType {
	return d.getContestableDetails(false)
}

// getContestableDetails returns all contestable details in the details based on the ownership
func (d *Details) getContestableDetails(isOwner bool) []ContestableDetailsType {
	contestableDetails := []ContestableDetailsType{}
	for _, it := range d.Premises {
		if it.ContestableDetails.SignedUp && it.SharedResourceDetails.Owner == isOwner {
			contestableDetails = append(contestableDetails, it.ContestableDetails)
		}
	}
	return contestableDetails
}

// IsPPMS checks if the provided premises is on PPMS
func (p *PremisesType) IsPPMS() bool {
	if !p.PpmsDetails.Exists || p.PpmsDetails.AccountNumber == "" {
		return false
	}
	return true
}

// generatePpmsDetails returns the PPMS details struct
func generatePpmsDetails(acc ebs.CustomerDetailsBpItem) PpmsDetailsType {
	var details PpmsDetailsType
	if frcpo.IsPPMS(acc) {
		details = PpmsDetailsType{
			Exists:        true,
			AccountNumber: sap.StripAccountNo(acc.AccountNo) + "P",
		}
	}
	return details
}

// NonPIIAddress mask premises address and address details
func (p *PremisesType) NonPIIAddress() {
	// Strip PII in the address
	address, a := sap.NonPIIAddress(p.Address)
	// Set Non PII address
	p.Address = address
	// Set Non PII address details
	p.AddressDetails.From(a)

	// Strip PII in accounts address
	for i, it := range p.Accounts {
		p.Accounts[i].Address, _ = sap.NonPIIAddress(it.Address)
	}
}

// SetAddressDetails sets the address details from the premises address
func (p *PremisesType) SetAddressDetails() {
	if p.Address == "" {
		return
	}
	// Deconstruct address
	a := sap.DeconstructAddress(p.Address)
	// Set address details
	p.AddressDetails.From(a)
}

// From sets the AddressDetails from a sap.Address
func (pa *AddressDetailsType) From(a sap.Address) {
	pa.Block = a.Block
	pa.Street = a.Street
	pa.Floor = a.Floor
	pa.Unit = a.Unit
	pa.Country = a.Country
	pa.Postal = a.Postal
}

