// gatewayAuthenticated is the authenticated gateway routes
func gatewayAuthenticated(r chi.Router) {
	r.Group(func(r chi.Router) {
		// Access token middleware
		r.Use(basiciam.RequireAccessToken(auth0.JWKSKeyFunc))
		// scope for mulesoft
		r.Use(basiciam.RequireClaimScope(auth0.ScopeM2MMulesoftUser))
		// SecurityContextInterceptor for mulesoft
		r.Use(interceptor.SecurityContextInterceptor)

		// Access token claims middleware
		r.Use(auth0.MulesoftClaimsMiddleware())

		// v2 routes already deprecated, no need put behind mulesoft
		r.Group(v1.GatewayAuthenticatedRoutes) //Added for Digital Signing, to be moved out of Jarvis as part of Jarvis 2.0
		r.Group(v3.GatewayAuthenticatedRoutes)
		r.Group(v4.GatewayAuthenticatedRoutes)
		r.Group(v5.GatewayAuthenticatedRoutes)
	})
}

// gatewayPublic is the public gateway routes
func gatewayPublic(r chi.Router) {
	r.Group(v1.GatewayPublicRoutes) //Added for Digital Signing, to be moved out of Jarvis as part of Jarvis 2.0
	r.Group(v3.GatewayPublicRoutes)
	r.Group(v4.GatewayPublicRoutes)
	r.Group(v5.GatewayPublicRoutes)
}

