	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/handler"
	chitracer "github.com/DataDog/dd-trace-go/contrib/go-chi/chi.v5/v2"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/cors"
	"github.com/pkg/errors"
)

var wd string

type DatadogAppConfig struct {
	ProjectTeam      string
	ProjectName      string
	SubComponentName string
}

func init() {
	var err error
	if wd, err = os.Getwd(); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "fs"))
	}
}

// Handler returns the http handler that handles all requests
func Handler() http.Handler {
	r := chi.NewRouter()

	//Add Datadog middleware for chi routes
	//Note: Dev env is not supported
	if os.Getenv("APPENV") != "dev" || os.Getenv("APPENV") != "test" {
		r.Use(chitracer.Middleware())
		log.Println("Added Datadog middleware for chi request tracking")
	}

	dbcfg, err := database.ConfigFromEnv()
	if err != nil {
		log.Fatalf("%s", fmt.Errorf("unable to load database config: %w", err))
	}
	maxOpen, err := strconv.Atoi(os.Getenv("DB_POOL_BYOB"))
	if err != nil {
		log.Fatalf("%s", fmt.Errorf("err in max open byob: %w", err))
	}
	dbcfg.MaxOpenConns = maxOpen
	maxIdle, err := strconv.Atoi(os.Getenv("DB_CONN_MAX_IDLE_BYOB"))
	if err != nil {
		log.Fatalf("%s", fmt.Errorf("err in max idle byob: %w", err))
	}
	dbcfg.MaxIdleConns = maxIdle
	byobDBPool, _, err := database.Conn("postgres", os.Getenv("DATABASE_URL"), dbcfg)
	if err != nil {
		log.Fatalf("%s", fmt.Errorf("unable to start database connection pool: %w", err))
	}

	r.Get("/status", handler.WrapHandler(health.Check(byobDBPool), ravenerrors.Wrapper()))

	r.Group(routes(byobDBPool))

	return r
}

// routes is the chi.Router.Group for all endpoints
func routes(byobDBConn database.BeginnerExecutor) func(r chi.Router) {
	return func(r chi.Router) {
		// Basic CORS
		cors := cors.New(cors.Options{
			AllowedOrigins:   []string{"*"},
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type", "X-CSRF-Token"},
			ExposedHeaders:   []string{"Link"},
			AllowCredentials: true,
			MaxAge:           300, // Maximum value not ignored by any of major browsers
		})
		r.Use(cors.Handler)

		// Register base middlewares
		r.Use(middleware.Recover())
		r.Use(tracing.Middleware())
		r.Use(middleware.RequestLogger())

		// Unversioned routes

		// Versioned routes
		r.Group(v2.Router)
		r.Group(v3.Router)
		r.Group(v4.Router)
		r.Group(v5.Router)

		// Static file handlers
		r.Group(fs)

		// gateway authenticated routes
		r.Route("/gateway/authenticated", gatewayAuthenticated)
		r.Route("/gateway/public", gatewayPublic)
	}
}

func fs(r chi.Router) {
	// Register middlewares
	r.Use(middleware.MaxAge(3600))

	handler.FileServer(r, "/", filepath.Join(wd, "static"))
}

func PrepareDataDogConfig() DatadogAppConfig {

	//Prepare datadog config for this service
	ddAppCfg := DatadogAppConfig{
		ProjectTeam:      os.Getenv("PROJECT_TEAM"),
		ProjectName:      os.Getenv("PROJECT_NAME"),
		SubComponentName: os.Getenv("PROJECT_COMPONENT"),
	}
	return ddAppCfg
}

