	ctx = emds.MockAMIDailyByMonth(ctx, &emds.AMIDailyByMonthRequest{AccountNumbers: []string{"IAMID1"}, StartMonth: "2019-01", EndMonth: "2019-01"}, mockedDaily, nil)
	ctx = emds.MockAMIHalfHourlyByDay(ctx, &emds.AMIHalfHourlyByDayRequest{AccountNumbers: []string{"IAMID2"}, StartDate: "2019-02-01", EndDate: "2019-02-09"}, mockedHalfHourly, nil)
