func TestDownloadCSV_Error(t *testing.T) {
	testCases := []struct {
		given    string
		owner    bool
		expected *web.Error
	}{
		{
			given: `iam_id,premises_id,start_date,end_date,grouped_by
1,2,3,4
`,
			owner:    true,
			expected: ErrCsvInvalid,
		},
		{
			given: `iam_id,premises_id,start_date,end_date,grouped_by
,2000011111,2019-01-01T00:00:00+08:00,2019-01-01T00:00:00+08:00,month
`,
			owner:    true,
			expected: ErrCsvInvalid,
		},
		{
			given: `iam_id,premises_id,start_date,end_date,grouped_by
auth0|iamid1,,2019-01-01T00:00:00+08:00,2019-01-01T00:00:00+08:00,month
`,
