			expected: bp.ErrPremiseUnauthorized,
		},
		{
			given: `iam_id,premises_id,start_date,end_date,grouped_by
auth0|iamid1,2000011111,2019-01-01T00:00:00+08:00,2019-01-01T00:00:00+08:00,month
