package stubs

import (
	"context"
	"crypto/tls"
	"log"
	"net/http"
	"net/url"
	"os"
	"strconv"
	"time"

	"code.in.spdigital.sg/sp-digital/golang/appenv"
	"code.in.spdigital.sg/sp-digital/jarvis-api/internal/pkg/auth0"
	"golang.org/x/oauth2"
	"golang.org/x/oauth2/clientcredentials"
)

var (
	// Client is the HTTP client instance for stubs
	Client *http.Client
	// LimitConnsPerHostClient is the HTTP client instance with MaxConnsPerHost for stubs
	LimitConnsPerHostClient *http.Client
	// InsecureClient is the HTTP client instance for skipping TLS verification on proxy
	InsecureClient *http.Client

	// BifrostClient is the HTTP OAuth2 client used to call Bifrost endpoints
	BifrostClient *http.Client
	// NotifyAPIClient is the HTTP OAuth2 client used to call notify-api endpoints
	NotifyAPIClient *http.Client
	// CRAPIClient is the HTTP OAuth2 client used to call cr-api proxy
	CRAPIClient *http.Client
	// SAPPOClient make calls directly to SAP PO via Express Route
	SAPPOClient *http.Client
	// SAPPOClient make calls directly to SAP PO via Express Route
	K2Client *http.Client
	// EMDSCRAPIClient is a dedicated HTTP OAuth2 client dedicated only for EMDS/BDL calls via cr-api proxy
	EMDSCRAPIClient *http.Client

	// ProfileAPIClient is the HTTP OAuth2 client used to call profile-api endpoints
	ProfileAPIClient *http.Client
	// PlatformBridgeClient is the HTTP OAuth2 client used to call platform bridge endpoints
	PlatformBridgeClient *http.Client
	// OneUpAPIClient is the HTTP OAuth2 client used to call 1up-api endpoints
	OneUpAPIClient *http.Client
	// DataServiceClient is a dedicated HTTP client for Data service calls (no auth required)
	DataServiceClient *http.Client
	// YCSClient is the HTTP OAuth2 client used to call YCS endpoints
	YCSClient *http.Client
	// CasperAPIClient is the HTTP OAuth2 client used to call Casper APIGW
	CasperAPIClient *http.Client

	// ConnTimeout defines our request timeout to endpoint
	ConnTimeout time.Duration
	// MaxConnsPerHost defines our max connection per host setting
	MaxConnsPerHost int
)

func init() {
	var err error
	ConnTimeout, err = time.ParseDuration(appenv.GetWithDefault("HTTPSTUB_CONN_TIMEOUT", "30s"))
	if err != nil {
		log.Fatalf(err.Error())
	}
	MaxConnsPerHost, err = strconv.Atoi(appenv.GetWithDefault("HTTPSTUB_MAX_CONN_PER_HOST", "5"))
	if err != nil {
		log.Fatalf(err.Error())
	}
	defaultTransport := http.DefaultTransport.(*http.Transport)

	insecureSkipVerify := false
	if os.Getenv("APPENV") == "dev" {
		insecureSkipVerify = true
	}

	Client = &http.Client{Timeout: ConnTimeout}

	LimitConnsPerHostClient = &http.Client{
		Timeout: ConnTimeout,
		Transport: &http.Transport{
			Proxy:                 defaultTransport.Proxy,
			DialContext:           defaultTransport.DialContext,
			MaxIdleConns:          defaultTransport.MaxIdleConns,
			IdleConnTimeout:       defaultTransport.IdleConnTimeout,
			ExpectContinueTimeout: defaultTransport.ExpectContinueTimeout,
			TLSHandshakeTimeout:   defaultTransport.TLSHandshakeTimeout,
			TLSClientConfig:       &tls.Config{InsecureSkipVerify: insecureSkipVerify},
			MaxConnsPerHost:       MaxConnsPerHost * 2 / 3, // Derived based on new relic throughput metrics
		},
	}

	SAPPOClient = &http.Client{
		Timeout: ConnTimeout,
		Transport: &http.Transport{
			Proxy:                 defaultTransport.Proxy,
			DialContext:           defaultTransport.DialContext,
			MaxIdleConns:          defaultTransport.MaxIdleConns,
			IdleConnTimeout:       defaultTransport.IdleConnTimeout,
			ExpectContinueTimeout: defaultTransport.ExpectContinueTimeout,
			TLSHandshakeTimeout:   defaultTransport.TLSHandshakeTimeout,
			TLSClientConfig:       &tls.Config{InsecureSkipVerify: insecureSkipVerify},
			MaxConnsPerHost:       MaxConnsPerHost * 2 / 3,
		},
	}

	K2Client = &http.Client{
		Timeout: ConnTimeout,
		Transport: &http.Transport{
			Proxy:                 defaultTransport.Proxy,
			DialContext:           defaultTransport.DialContext,
			MaxIdleConns:          defaultTransport.MaxIdleConns,
			IdleConnTimeout:       defaultTransport.IdleConnTimeout,
			ExpectContinueTimeout: defaultTransport.ExpectContinueTimeout,
			TLSHandshakeTimeout:   defaultTransport.TLSHandshakeTimeout,
			TLSClientConfig:       &tls.Config{InsecureSkipVerify: insecureSkipVerify},
			MaxConnsPerHost:       1,
		},
	}

	EMDSClient := &http.Client{
		Timeout: ConnTimeout,
		Transport: &http.Transport{
			Proxy:                 defaultTransport.Proxy,
			DialContext:           defaultTransport.DialContext,
			MaxIdleConns:          defaultTransport.MaxIdleConns,
			IdleConnTimeout:       defaultTransport.IdleConnTimeout,
			ExpectContinueTimeout: defaultTransport.ExpectContinueTimeout,
			TLSHandshakeTimeout:   defaultTransport.TLSHandshakeTimeout,
			TLSClientConfig:       &tls.Config{InsecureSkipVerify: insecureSkipVerify},
		},
	}

	// configure OAuth2 HTTP clients
	// Use the stubs.Client as base HTTP client
	ctx := context.WithValue(context.Background(), oauth2.HTTPClient, Client)
	BifrostClient = bifrostOAuth2Config().Client(ctx)
	NotifyAPIClient = notifyAPIOAuth2Config().Client(ctx)
	ProfileAPIClient = profileAPIOAuth2Config().Client(ctx)
	PlatformBridgeClient = platformBridgeOAuth2Config().Client(ctx)
	OneUpAPIClient = oneUpAPIOAuth2Config().Client(ctx)
	DataServiceClient = Client
	YCSClient = ycsOAuth2Config().Client(ctx)

	// Separate http client for other Crapi proxy endpoints excluding EMDS/BDL
	crapiCtx := context.WithValue(context.Background(), oauth2.HTTPClient, LimitConnsPerHostClient)
	if os.Getenv("APPENV") == "test" {
		CRAPIClient = crAPIOAuth2Config().Client(ctx)
	} else {
		CRAPIClient = crAPIOAuth2Config().Client(crapiCtx)
	}

	// Separate http client for EMDS endpoints via Express Route
	emdsCtx := context.WithValue(context.Background(), oauth2.HTTPClient, EMDSClient)
	if os.Getenv("APPENV") == "test" {
		EMDSCRAPIClient = emdsAPIOAuth2Config().Client(ctx)
	} else {
		EMDSCRAPIClient = emdsAPIOAuth2Config().Client(emdsCtx)
	}

	// Separate http client for SMRD/BDL endpoints called via Casper APIGW
	casperCtx := context.WithValue(context.Background(), oauth2.HTTPClient, LimitConnsPerHostClient)
	if os.Getenv("APPENV") == "test" {
		CasperAPIClient = casperAPIOAuth2Config().Client(ctx)
	} else {
		CasperAPIClient = casperAPIOAuth2Config().Client(casperCtx)
	}

	BifrostClient.Timeout = ConnTimeout
	NotifyAPIClient.Timeout = ConnTimeout
	CRAPIClient.Timeout = ConnTimeout
	EMDSCRAPIClient.Timeout = ConnTimeout
	ProfileAPIClient.Timeout = ConnTimeout
	PlatformBridgeClient.Timeout = ConnTimeout
	OneUpAPIClient.Timeout = ConnTimeout
	DataServiceClient.Timeout = ConnTimeout
	YCSClient.Timeout = ConnTimeout
	CasperAPIClient.Timeout = ConnTimeout
}

