		meterinstallationdetails.DivisionElectric: utilities.TypeElectric,
		meterinstallationdetails.DivisionGas:      utilities.TypeGas,
		meterinstallationdetails.DivisionWater:    utilities.TypeWater,
	}
)

type mdChanData struct {
	premisesID        string
	amiElec           bool
	intervalUtilities []string
	srlp              bool
}

// retrieveMeterDetails retrieves the premises's meter installation details (i.e. interval utilities, SMMU, AMI, rate category)
func retrieveMeterDetails(ctx context.Context, g *errgroup.Group, accType string, p PremisesType, data mdChanData, out chan mdChanData) {
	logger := loglib.GetLogger(ctx)

	var acc AccountsType
	var ok bool
	if accType == frcpo.SystemMSSL {
		acc, ok = p.GetActiveMSSLAccount()
	} else {
		acc, ok = p.GetActiveEBSAccount()
	}
	if !ok {
		return
	}

	data.intervalUtilities = []string{}

	g.Go(func() error {
		// Retrieve meter installation details for account number
		resp, err := meterinstallationdetails.MakeRequest(ctx, meterinstallationdetails.Request{
			AccountNo: acc.AccountNumber,
		})
		if err != nil {
			logger.Errorf("Encountered error retrieving meter installation details for %s: %s", acc.AccountNumber, err.Error())
			return err
		}
		if resp.MtInstallationmeterreadresponse.Errmsg.String != "" {
			logger.Errorf("Encountered error retrieving meter installation details for %s: %s", acc.AccountNumber, resp.MtInstallationmeterreadresponse.Errmsg.String)
			// Commented out erroring out (basically ignore and log error for now) and proceed to evaluate the list of meters
			// TODO: Ask Subash (or whoever in ITD) what does "Invalid Input Parameter" mean
			// return errors.New(resp.MtInstallationmeterreadresponse.Errmsg.String)
		}
		meters := resp.MtInstallationmeterreadresponse.Item.Array

		// Populate meter interval utilities
		intervalUtilities, err := evaluateIntervalUtilities(ctx, acc, meters)
		if err != nil {
			return err
		}
		data.intervalUtilities = intervalUtilities

		m, ok := findActiveElecMeter(meters)
		if ok {
			data.amiElec = meterinstallationdetails.IsAMI(m)
			data.srlp = meterinstallationdetails.IsSRLP(m)
		}

		out <- data
		return nil
	})
}

// findActiveElecMeter finds the active elec meter from the array provided
func findActiveElecMeter(meters []meterinstallationdetails.ItemType) (meterinstallationdetails.ItemType, bool) {
	now := time.Now()
	for _, it := range meters {
		// Check meter installation utility type
		utilityType, ok := meterInstallationUtilityLookup[it.Division.String]
		if !ok {
			// Skip unsupported/unknown utility type
			continue
		}

		// Active elec meter
		if utilityType == utilities.TypeElectric &&
			meterinstallationdetails.IsMeterActive(it, now) {
			return it, true
		}
	}
	return meterinstallationdetails.ItemType{}, false
}

// evaluateIntervalUtilities evaluates the utilities for an account that has interval data (half-hourly)
func evaluateIntervalUtilities(ctx context.Context, acc AccountsType, meters []meterinstallationdetails.ItemType) ([]string, error) {
	result := []string{}
	// Iterate meter installation details
	now := time.Now()
	for _, it := range meters {
		// Check meter installation utility type
		utilityType, ok := meterInstallationUtilityLookup[it.Division.String]
		if !ok {
			// Skip unsupported/unknown utility type
			continue
		}

		// Only allows meters on either:
		// - AMI
		// - SRLP rate category
		// Note that `interval_utilities` indicates that the following utilities can retrieve half-hourly data from BDL
		// As of 20190115, it is no longer limited to AMI alone, but we're also opening it up for SRLP meters (even mechanical)
		if !meterinstallationdetails.IsAMI(it) && !meterinstallationdetails.IsSRLP(it) {
			// Skip invalid meter configuration
			continue
		}

		// Clean-up outdated/replaced AMI meter
		if !meterinstallationdetails.IsMeterActive(it, now) {
			// Skip inactive meter
			continue
		}

		// Register AMI meter
		result = append(result, utilityType)
	}

	// Sort utilities
	sort.Strings(result)
	return result, nil
}

CREATE TABLE IF NOT EXISTS products (
    id text CHECK (id::text <> ''::text) PRIMARY KEY,
    name text CHECK (name::text <> ''::text) NOT NULL,
    group_id text CHECK (group_id::text <> ''::text),
    type text CHECK (type::text <> ''::text) NOT NULL,
    subscription_frequency text CHECK (subscription_frequency::text <> ''::text),
    subscription_month_offset integer default 0 NOT NULL,
    description text CHECK (description::text <> ''::text) NOT NULL,
    price int NOT NULL,
    is_deleted boolean default 'false' NOT NULL,
    created_by text CHECK (created_by::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN products.name IS 'Name of the product';
COMMENT ON COLUMN products.group_id IS 'Group ID the product belongs to';
COMMENT ON COLUMN products.type IS 'Type of the product';
COMMENT ON COLUMN products.subscription_frequency IS 'Subscription frequency of the product (e.g. MONTHLY, YEARLY)';
COMMENT ON COLUMN products.subscription_month_offset IS 'Offset of when a subscription will start in month (e.g. 1 = 1 month)';
COMMENT ON COLUMN products.description IS 'Description of the product';
COMMENT ON COLUMN products.price IS 'Unit price of the product in cents';

CREATE SEQUENCE IF NOT EXISTS order_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;

CREATE TABLE IF NOT EXISTS orders (
    id text CHECK (id::text <> ''::text) PRIMARY KEY,
    iam_id text CHECK (iam_id::text <> ''::text) NOT NULL,
    status text CHECK (status::text <> ''::text) NOT NULL,
    payment_status text CHECK (payment_status::text <> ''::text) NOT NULL,
    total_price int NOT NULL,
    customer_details json NOT NULL,
    payment_details json,
    created_by text CHECK (created_by::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN orders.iam_id IS 'IAM ID of the user who place the order';
COMMENT ON COLUMN orders.status IS 'Status of the order';
COMMENT ON COLUMN orders.total_price IS 'Total price of the order in cents';
COMMENT ON COLUMN orders.payment_status IS 'Payment status of the order';
COMMENT ON COLUMN orders.customer_details IS 'Snapshot of customers shipping details e.g. shipping address, customer name, customer phone numer (will be encrypted)';


CREATE TABLE IF NOT EXISTS order_items (
    id BIGSERIAL PRIMARY KEY,
    order_id text CHECK (order_id::text <> ''::text) references orders(id) NOT NULL,
    product_id text CHECK (product_id::text <> ''::text) references products(id) NOT NULL,
    product_details json NOT NULL,
    price int NOT NULL,
    total_price int NOT NULL,
    quantity INTEGER NOT NULL,
    created_by text CHECK (created_by::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN order_items.order_id IS 'Order ID of the order the order item is part of';
COMMENT ON COLUMN order_items.product_id IS 'Product ID of the product the order item references';
COMMENT ON COLUMN order_items.product_details IS 'Snapshot of the product at the time of order creation';
COMMENT ON COLUMN order_items.price IS 'Unit price of the order item in cents';
COMMENT ON COLUMN order_items.total_price IS 'Total price (unit price * quantity) of the order item in cents';
COMMENT ON COLUMN order_items.quantity IS 'Quantity of the order item';

CREATE TABLE IF NOT EXISTS ambi_devices (
    id text CHECK (id::text <> ''::text) NOT NULL PRIMARY KEY,
    premises_id text CHECK (premises_id::text <> ''::text) NOT NULL,
    location_id text CHECK (location_id::text <> ''::text) NOT NULL,
    room_name text CHECK (room_name::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN ambi_devices.id IS 'Real device ID of the AMBI device';
COMMENT ON COLUMN ambi_devices.premises_id IS 'Premise ID of the user';
COMMENT ON COLUMN ambi_devices.location_id IS 'Location ID provided by AMBI to identify the location of the device';
COMMENT ON COLUMN ambi_devices.room_name IS 'Room name of where the device resides';

CREATE SEQUENCE IF NOT EXISTS ambi_subscription_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;
CREATE TABLE IF NOT EXISTS ambi_subscriptions (
    id text CHECK (id::text <> ''::text) PRIMARY KEY,
    iam_id text CHECK (iam_id::text <> ''::text) NOT NULL,
    product_id text CHECK (product_id::text <> ''::text) references products(id) NOT NULL,
    product_details json NOT NULL,
    ambi_device_id text CHECK (ambi_device_id::text <> ''::text) UNIQUE references ambi_devices(id),
    external_transaction_id text CHECK (external_transaction_id::text <> ''::text),
    active boolean default 'false' NOT NULL,
    created_by text CHECK (created_by::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN ambi_subscriptions.iam_id IS 'IAM ID of the user who owns the subscription';
COMMENT ON COLUMN ambi_subscriptions.product_id IS 'The SKU of the subscription';
COMMENT ON COLUMN ambi_subscriptions.product_details IS 'Snapshot of the subscription at the time of subscription creation';
COMMENT ON COLUMN ambi_subscriptions.ambi_device_id IS 'The AMBI device the subscription is for';
COMMENT ON COLUMN ambi_subscriptions.active IS 'If subscription is active or not';
COMMENT ON COLUMN ambi_subscriptions.external_transaction_id IS 'The transaction ID returned from Bolt';

