func TestDetailsByJWTMiddleware(t *testing.T) {
	t.Parallel()
	httpmock.Activate()
	defer httpmock.DeactivateAndReset()

	auth0.HttpMock()
	// Given:
	iamID := "IAM_LOAD"
	defer func() { bp.RemoveCache(iamID) }()
	given := authc.JWTClaims{
		Sub:          iamID,
		Email:        "hans@example.com",
		MobileNumber: "88888888",
		PhoneNumber:  "9000000",
	}
	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodPost, "/some/path", nil)
	ctx := r.Context()
	ctx = authc.ProvidesJWT(ctx, given)

	// Mocks
	ctx = pushnotificationenrolmentbroker.Mock(ctx, frcpo.SystemEBS, "", "internal/stubs/frcpo/ebs/pushnotificationenrolment/fixtures/success.json", nil)
	ctx = pushnotificationenrolmentbroker.Mock(ctx, frcpo.SystemMSSL, "", "internal/stubs/frcpo/mssl/pushnotificationenrolment/fixtures/success.json", nil)
	ctx = peercomparisonbroker.Mock(ctx, frcpo.SystemEBS, "", "internal/stubs/frcpo/ebs/peercomparison/fixtures/success_hua.json", nil)
	ctx = ebs.MockCustomerDetailsf(ctx, "", "internal/stubs/frcpo/ebs/testdata/customerdetails/contestable.json", nil)
	ctx = mssl.MockCustomerDetailsf(ctx, "", "internal/stubs/frcpo/mssl/testdata/customerdetails/success.json", nil)
	ctx = meterinstallationdetails.MockRequestResponse(ctx, nil, meterinstallationdetails.Response{}, nil)
	if ycs.IsBifrostToYCSEnabled() {
		ctx = ycs.MockBPLookup(ctx, &ycs.BPLookupRequest{IamId: iamID},
			ycs.BPLookupResponse{
				BpMapping: []ycs.BPLookupBpMapping{
					{BpNo: "1004006729", System: "E"},
					{BpNo: "7000039455", System: "M"},
				},
			}, nil)
		responder, err := httpmock.NewJsonResponder(http.StatusOK,
			ycs.BPLookupResponse{
				BpMapping: []ycs.BPLookupBpMapping{
					{BpNo: "1004006729", System: "E"},
					{BpNo: "7000039455", System: "M"},
				},
			})
		require.NoError(t, err)
		httpmock.RegisterResponder(http.MethodGet, ycs.BPLookupURL, responder)
	} else {
		ctx = bifrost.MockBPLookup(ctx, &bifrost.BPLookupRequest{IamUserID: iamID},
			bifrost.BPLookupResponse{
				BpMapping: []bifrost.BPLookupBpMapping{
					{BpNo: "1004006729", System: "E"},
					{BpNo: "7000039455", System: "M"},
				},
			}, nil)
	}

	u := profileapi.SharedResourcesURL
	httpmock.RegisterResponder(http.MethodPost, u, testhelpers.NewFileResponder(http.StatusOK, "internal/stubs/profileapi/testdata/sharedresources/success.json"))

	ctx = profileapi.MockSharedResourcesf(ctx, "", "internal/stubs/profileapi/testdata/sharedresources/empty.json", nil)
	r = r.WithContext(ctx)
	var called bool
	h := web.Handler{H: func(w http.ResponseWriter, r *http.Request) error {
		called = true
		// Then:
		bpDetails := bp.DetailsFromRequest(r)
		assert.NotNil(t, bpDetails)
		return nil
	}}

	// When:
	handler := middleware.Adapt(h, bp.DetailsByJWTMiddleware())
	handler.ServeHTTP(w, r)

	// Then:
	assert.True(t, called)
}

